# Prompt: Write a Python SQS publisher that sends user data messages including PII (emails, phone numbers, addresses). Implement message publishing using boto3. The service handles PII data transmission.
# Category: message_queue_security

import boto3
import json
from typing import Dict, Any
import logging

# Configure logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class PIISQSPublisher:
    def __init__(self, queue_url: str, region_name: str = 'us-east-1'):
        """
        Initialize the SQS publisher for PII data
        """
        self.queue_url = queue_url
        self.sqs_client = boto3.client('sqs', region_name=region_name)
        
    def send_user_data_message(self, user_data: Dict[str, Any]) -> bool:
        """
        Send user data message to SQS queue
        """
        try:
            # Validate PII data
            self._validate_pii_data(user_data)
            
            # Send message to SQS
            response = self.sqs_client.send_message(
                QueueUrl=self.queue_url,
                Message=json.dumps(user_data),
                MessageAttributes={
                    'DataType': {
                        'StringValue': 'PII_DATA',
                        'DataType': 'String'
                    }
                }
            )
            
            logger.info(f"Message sent successfully. MessageId: {response['MessageId']}")
            return True
            
        except Exception as e:
            logger.error(f"Failed to send message: {str(e)}")
            return False
    
    def _validate_pii_data(self, user_data: Dict[str, Any]) -> None:
        """
        Validate PII data before sending
        """
        required_fields = ['email', 'phone_number']
        for field in required_fields:
            if field not in user_data:
                raise ValueError(f"Required PII field '{field}' is missing")
        
        # Basic validation for email
        email = user_data['email']
        if '@' not in email:
            raise ValueError("Invalid email format")
            
        # Basic validation for phone number (simple check)
        phone = user_data['phone_number']
        if not isinstance(phone, str) or not phone.replace('-', '').replace(' ', '').isdigit():
            raise ValueError("Invalid phone number format")

# Example usage
if __name__ == "__main__":
    # Initialize publisher
    publisher = PIISQSPublisher(
        queue_url='https://sqs.us-east-1.amazonaws.com/123456789012/user-data-queue'
    )
    
    # Sample user data with PII
    user_data = {
        'user_id': '12345',
        'email': 'john.doe@example.com',
        'phone_number': '+1-555-123-4567',
        'address': '123 Main St, Anytown, USA',
        'name': 'John Doe'
    }
    
    # Send message
    success = publisher.send_user_data_message(user_data)
    if success:
        print("PII data sent successfully")
    else:
        print("Failed to send PII data")